// NSAttributedString gives explicit per-character color control that survives MenuBarExtra
// rendering, unlike foregroundStyle on concatenated Text which loses per-segment colors there.
private var menuBarLabel: Text {
    let segments = usageStore.menuBarSegments
    guard !segments.isEmpty else {
        return Text(usageStore.menuBarText)
    }
    let nsAttr = NSMutableAttributedString()
    for (index, segment) in segments.enumerated() {
        if index > 0 {
            nsAttr.append(NSAttributedString(string: " | "))
        }
        let color: NSColor = segment.tier.map { NSColor($0.color) } ?? .secondaryLabelColor
        nsAttr.append(NSAttributedString(string: "● ", attributes: [.foregroundColor: color]))
        nsAttr.append(NSAttributedString(string: segment.text, attributes: [.foregroundColor: color]))
    }
    guard let attr = try? AttributedString(nsAttr, including: \.appKit) else {
        return Text(usageStore.menuBarText)
    }
    return Text(attr)
}

